code_changes.content:
[
  {
    "file": "ghost/core/core/server/api/endpoints/comment-likes.js",
    "line": 10,
    "severity": "high",
    "description": "Incorrect cache control headers on read-only endpoint. The browse action uses 'cacheInvalidate: false' which is not a valid HTTP header. For a read-only admin endpoint returning sensitive moderation data (comment likers), proper cache control headers must be explicitly set to control caching behavior. Without correct cache control headers, the endpoint may not follow Ghost's API conventions and could result in inappropriate caching of sensitive admin data.",
    "fix_patch": "--- a/ghost/core/core/server/api/endpoints/comment-likes.js
+++ b/ghost/core/core/server/api/endpoints/comment-likes.js
@@ -8,7 +8,7 @@ const controller = {
     docName: 'comment_likes',
     browse: {
         headers: {
-            cacheInvalidate: false
+            'Cache-Control': 'public, max-age=0'
         },
         options: [
             'id',
"
  }
]

